import { Link, useLocation } from 'react-router-dom'
import { useEffect, useState } from 'react'
import { useTranslation } from '../i18n/useTranslation'
import { defaultLang } from '../i18n/translations'
import { getFaq, getHomeCards, getHomePageContent } from '../api/cms'
import LandingBelowFold from './LandingBelowFold'
import './HomePage.css'
import './CorporateHomePage.css'

/**
 * Corporate landing: hero, feature strip, CMS home HTML, FAQ + cards from CMS (same API as marketing sites).
 */
export default function CorporateHomePage() {
  const lang = defaultLang
  const location = useLocation()
  const t = useTranslation(lang)
  const [cmsHtml, setCmsHtml] = useState('')
  const [landingFaq, setLandingFaq] = useState([])
  const [landingCards, setLandingCards] = useState([])
  const [cardsSectionTitle, setCardsSectionTitle] = useState('')
  const [faqOpenIndex, setFaqOpenIndex] = useState(null)

  useEffect(() => {
    document.documentElement.lang = lang
  }, [lang])

  useEffect(() => {
    let cancelled = false
    Promise.all([
      getHomePageContent(lang, location.pathname).catch(() => ({})),
      getFaq(lang).catch(() => ({ faq: [] })),
      getHomeCards(lang).catch(() => ({ cards: [], section: {} })),
    ])
      .then(([homeRes, faqRes, cardsRes]) => {
        if (cancelled) return
        setCmsHtml(typeof homeRes?.content === 'string' ? homeRes.content : '')
        const rawFaq = Array.isArray(faqRes?.faq) ? faqRes.faq : []
        setLandingFaq(rawFaq)
        const rawCards = Array.isArray(cardsRes?.cards) ? cardsRes.cards : []
        setLandingCards(rawCards)
        const st = cardsRes?.section && typeof cardsRes.section === 'object' ? cardsRes.section.title : ''
        setCardsSectionTitle(typeof st === 'string' ? st : '')
      })
    return () => { cancelled = true }
  }, [lang, location.pathname])

  const faqItems = landingFaq.length > 0
    ? landingFaq.map((item) => ({
      q: item.question ?? item.q ?? '',
      a: item.answer ?? item.a ?? '',
    })).filter((x) => x.q || x.a)
    : []

  const base = ''

  const features = [
    {
      to: `${base}/platform`,
      title: t('corporate.feature1Title'),
      body: t('corporate.feature1Body'),
    },
    {
      to: `${base}/consultancy`,
      title: t('corporate.feature2Title'),
      body: t('corporate.feature2Body'),
    },
    {
      to: `${base}/solutions`,
      title: t('corporate.feature3Title'),
      body: t('corporate.feature3Body'),
    },
  ]

  return (
    <div className="corporate-home">
      <section className="corporate-home-hero" aria-labelledby="corporate-home-heading">
        <div className="corporate-home-hero-bg" aria-hidden="true" />
        <div className="corporate-home-hero-content">
          <p className="corporate-home-eyebrow">{t('corporate.homeEyebrow')}</p>
          <h1 id="corporate-home-heading" className="corporate-home-title">
            {t('corporate.homeHeroTitle')}
          </h1>
          <p className="corporate-home-subtitle">{t('corporate.homeHeroSubtitle')}</p>
          <div className="corporate-home-cta-row">
            <Link to={`${base}/contact`} className="corporate-home-btn corporate-home-btn--primary">
              {t('corporate.ctaContact')}
            </Link>
            <Link to={`${base}/platform`} className="corporate-home-btn corporate-home-btn--ghost">
              {t('corporate.ctaPlatform')}
            </Link>
          </div>
        </div>
      </section>

      <section className="corporate-home-features" aria-labelledby="corporate-features-heading">
        <div className="corporate-home-features-inner">
          <h2 id="corporate-features-heading" className="corporate-home-features-title">
            {t('corporate.featuresHeading')}
          </h2>
          <ul className="corporate-home-feature-grid">
            {features.map((f) => (
              <li key={f.to}>
                <Link to={f.to} className="corporate-home-feature-card">
                  <span className="corporate-home-feature-card-title">{f.title}</span>
                  <span className="corporate-home-feature-card-body">{f.body}</span>
                  <span className="corporate-home-feature-card-cta">{t('corporate.featureCta')}</span>
                </Link>
              </li>
            ))}
          </ul>
        </div>
      </section>

      <div className="corporate-home-cms-stack">
        <LandingBelowFold
          t={t}
          homeContent={cmsHtml}
          faqItems={faqItems}
          faqOpenIndex={faqOpenIndex}
          setFaqOpenIndex={setFaqOpenIndex}
          cards={landingCards}
          showHowSection={false}
          cardsTitle={cardsSectionTitle}
        />
      </div>
    </div>
  )
}
